import { useState, useEffect } from 'react';

function getValue<T,>(key: string, initialValue: T | (() => T)): T {
    const savedValue = localStorage.getItem(key);
    if (savedValue) {
        try {
            return JSON.parse(savedValue) as T;
        } catch (error) {
            console.error('Error parsing JSON from localStorage', error);
            localStorage.removeItem(key);
        }
    }

    if (initialValue instanceof Function) {
        return initialValue();
    }
    return initialValue;
}

export function useLocalStorage<T,>(key: string, initialValue: T | (() => T)): [T, React.Dispatch<React.SetStateAction<T>>] {
    const [value, setValue] = useState<T>(() => getValue(key, initialValue));

    useEffect(() => {
        try {
            localStorage.setItem(key, JSON.stringify(value));
        } catch (error) {
            console.error('Error setting item to localStorage', error);
        }
    }, [key, value]);

    return [value, setValue];
}

import React, { createContext, useContext } from 'react';
import { useLocalStorage } from '../hooks/useLocalStorage';
import { CompanyProfile } from '../types';
import { DEFAULT_COMPANY_PROFILE } from '../constants';

interface SettingsContextType {
    profile: CompanyProfile;
    setProfile: React.Dispatch<React.SetStateAction<CompanyProfile>>;
}

const SettingsContext = createContext<SettingsContextType | undefined>(undefined);

export const SettingsProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [profile, setProfile] = useLocalStorage<CompanyProfile>('company-profile', DEFAULT_COMPANY_PROFILE);

    return (
        <SettingsContext.Provider value={{ profile, setProfile }}>
            {children}
        </SettingsContext.Provider>
    );
};

export const useSettings = (): SettingsContextType => {
    const context = useContext(SettingsContext);
    if (!context) {
        throw new Error('useSettings must be used within a SettingsProvider');
    }
    return context;
};

const units = ['', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine'];
const teens = ['Ten', 'Eleven', 'Twelve', 'Thirteen', 'Fourteen', 'Fifteen', 'Sixteen', 'Seventeen', 'Eighteen', 'Nineteen'];
const tens = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];

function convertLessThanOneThousand(n: number): string {
    let result = '';
    if (n >= 100) {
        result += units[Math.floor(n / 100)] + ' Hundred ';
        n %= 100;
    }
    if (n >= 20) {
        result += tens[Math.floor(n / 10)] + ' ';
        n %= 10;
    }
    if (n >= 10) {
        result += teens[n - 10] + ' ';
        n = 0;
    }
    if (n > 0) {
        result += units[n] + ' ';
    }
    return result;
}

export function numberToWords(num: number): string {
    if (num === 0) return 'Zero Rupees Only';
    if (num < 0) return 'Minus ' + numberToWords(Math.abs(num));

    let integerPart = Math.floor(num);
    const decimalPart = Math.round((num - integerPart) * 100);

    let result = '';
    if (integerPart >= 10000000) {
        result += convertLessThanOneThousand(Math.floor(integerPart / 10000000)) + 'Crore ';
        integerPart %= 10000000;
    }
    if (integerPart >= 100000) {
        result += convertLessThanOneThousand(Math.floor(integerPart / 100000)) + 'Lakh ';
        integerPart %= 100000;
    }
    if (integerPart >= 1000) {
        result += convertLessThanOneThousand(Math.floor(integerPart / 1000)) + 'Thousand ';
        integerPart %= 1000;
    }
    result += convertLessThanOneThousand(integerPart);

    result = result.trim() + ' Rupees';

    if (decimalPart > 0) {
        result += ' and ' + convertLessThanOneThousand(decimalPart).trim() + ' Paise';
    }

    return result.replace(/\s+/g, ' ').trim() + ' Only';
}

import { jsPDF } from 'jspdf';
import 'jspdf-autotable';
import { CompanyProfile, Document, LineItem } from '../types';
import { numberToWords } from './numberToWords';

// Extend jsPDF with autoTable
declare module 'jspdf' {
    interface jsPDF {
        autoTable: (options: any) => jsPDF;
    }
}

export const generatePdf = (docData: Document, profile: CompanyProfile) => {
    const doc = new jsPDF({
        orientation: 'p',
        unit: 'mm',
        format: 'a4'
    });

    const pageHeight = doc.internal.pageSize.getHeight();
    const pageWidth = doc.internal.pageSize.getWidth();
    const margin = 10;

    let yPos = margin;

    // Header
    if (profile.logo) {
        try {
            doc.addImage(profile.logo, 'PNG', margin, yPos, 30, 30);
        } catch (e) {
            console.error("Error adding logo image:", e);
        }
    }
    doc.setFontSize(18);
    doc.setFont('helvetica', 'bold');
    doc.text(profile.name, pageWidth / 2, yPos + 10, { align: 'center' });
    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`${profile.address}, ${profile.cityStatePincode}`, pageWidth / 2, yPos + 16, { align: 'center' });
    doc.text(`Email: ${profile.email} | Phone: ${profile.phone}`, pageWidth / 2, yPos + 21, { align: 'center' });
    if (docData.gstType === 'gst') {
      doc.text(`GSTIN: ${profile.gstin}`, pageWidth / 2, yPos + 26, { align: 'center' });
    }

    yPos += 40;
    doc.setDrawColor(200);
    doc.line(margin, yPos, pageWidth - margin, yPos);
    yPos += 5;

    // Document Title
    const docTitle = `${docData.gstType.toUpperCase()} ${docData.docType.charAt(0).toUpperCase() + docData.docType.slice(1)}`;
    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.text(docTitle, pageWidth / 2, yPos, { align: 'center' });
    yPos += 10;

    // Seller & Customer Details
    doc.setFontSize(10);
    doc.setFont('helvetica', 'bold');
    doc.text('Customer Details (Bill To):', margin, yPos);

    doc.setFont('helvetica', 'normal');
    doc.text(docData.customer.name, margin, yPos + 5);
    doc.text(docData.customer.address, margin, yPos + 10);
    doc.text(docData.customer.cityStatePincode, margin, yPos + 15);
    if(docData.customer.gstin) {
      doc.text(`GSTIN: ${docData.customer.gstin}`, margin, yPos + 20);
    }

    const rightColX = pageWidth - margin - 70;
    doc.setFont('helvetica', 'bold');
    doc.text(`${docData.docType === 'invoice' ? 'Invoice' : 'Quotation'} No:`, rightColX, yPos);
    doc.text('Date:', rightColX, yPos + 5);
    if (docData.docType === 'invoice') {
        doc.text('Due Date:', rightColX, yPos + 10);
    } else {
        doc.text('Valid Till:', rightColX, yPos + 10);
    }

    doc.setFont('helvetica', 'normal');
    doc.text(docData.docNumber, rightColX + 30, yPos, { align: 'left' });
    doc.text(new Date(docData.date).toLocaleDateString('en-GB'), rightColX + 30, yPos + 5, { align: 'left' });
     if (docData.docType === 'invoice' && docData.dueDate) {
        doc.text(new Date(docData.dueDate).toLocaleDateString('en-GB'), rightColX + 30, yPos + 10, { align: 'left' });
    } else if (docData.docType === 'quotation' && docData.validTill) {
        doc.text(new Date(docData.validTill).toLocaleDateString('en-GB'), rightColX + 30, yPos + 10, { align: 'left' });
    }

    yPos += 30;

    // Items Table
    const subtotal = docData.items.reduce((acc, item) => acc + item.quantity * item.rate, 0);
    let totalTax = 0;

    const tableHead = docData.gstType === 'gst'
        ? [['#', 'Item & Description', 'HSN/SAC', 'Qty', 'Rate (₹)', 'GST (%)', 'Amount (₹)']]
        : [['#', 'Item & Description', 'Qty', 'Rate (₹)', 'Amount (₹)']];

    const tableBody = docData.items.map((item, index) => {
        const amount = item.quantity * item.rate;
        if (docData.gstType === 'gst') {
            const tax = amount * (item.gstRate / 100);
            totalTax += tax;
            return [index + 1, item.description, item.hsn, item.quantity, item.rate.toFixed(2), `${item.gstRate}%`, amount.toFixed(2)];
        } else {
            return [index + 1, item.description, item.quantity, item.rate.toFixed(2), amount.toFixed(2)];
        }
    });

    doc.autoTable({
        head: tableHead,
        body: tableBody,
        startY: yPos,
        theme: 'grid',
        headStyles: { fillColor: [22, 163, 74], textColor: 255 },
        styles: { fontSize: 9, cellPadding: 2 },
        columnStyles: {
            0: { cellWidth: 10 },
            1: { cellWidth: docData.gstType === 'gst' ? 60 : 100 },
        },
    });

    yPos = (doc as any).lastAutoTable.finalY + 10;

    // Totals
    const grandTotal = subtotal + totalTax;
    const totalsRightX = pageWidth - margin;
    const totalsLeftX = totalsRightX - 50;

    doc.setFontSize(10);
    doc.setFont('helvetica', 'bold');

    doc.text('Subtotal:', totalsLeftX, yPos, { align: 'right' });
    doc.setFont('helvetica', 'normal');
    doc.text(`₹${subtotal.toFixed(2)}`, totalsRightX, yPos, { align: 'right' });
    yPos += 6;

    if (docData.gstType === 'gst') {
        if (docData.isInterstate) {
            doc.setFont('helvetica', 'bold');
            doc.text('IGST:', totalsLeftX, yPos, { align: 'right' });
            doc.setFont('helvetica', 'normal');
            doc.text(`₹${totalTax.toFixed(2)}`, totalsRightX, yPos, { align: 'right' });
            yPos += 6;
        } else {
            doc.setFont('helvetica', 'bold');
            doc.text('CGST:', totalsLeftX, yPos, { align: 'right' });
            doc.setFont('helvetica', 'normal');
            doc.text(`₹${(totalTax / 2).toFixed(2)}`, totalsRightX, yPos, { align: 'right' });
            yPos += 6;

            doc.setFont('helvetica', 'bold');
            doc.text('SGST:', totalsLeftX, yPos, { align: 'right' });
            doc.setFont('helvetica', 'normal');
            doc.text(`₹${(totalTax / 2).toFixed(2)}`, totalsRightX, yPos, { align: 'right' });
            yPos += 6;
        }
    }

    doc.setLineWidth(0.5);
    doc.line(totalsLeftX - 10, yPos, totalsRightX, yPos);
    yPos += 6;

    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.text('Grand Total:', totalsLeftX, yPos, { align: 'right' });
    doc.text(`₹${grandTotal.toFixed(2)}`, totalsRightX, yPos, { align: 'right' });
    yPos += 10;

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text('Amount in words:', margin, yPos);
    doc.setFont('helvetica', 'bold');
    doc.text(numberToWords(grandTotal), margin, yPos + 5);

    yPos += 15;

    // Bank Details & Signature
    const bottomY = pageHeight - 40;

    doc.setFontSize(9);
    doc.setFont('helvetica', 'bold');
    doc.text('Bank Details:', margin, bottomY);
    doc.setFont('helvetica', 'normal');
    doc.text(`Bank Name: ${profile.bankName}`, margin, bottomY + 4);
    doc.text(`A/c No: ${profile.accountNumber}`, margin, bottomY + 8);
    doc.text(`Branch: ${profile.branch}`, margin, bottomY + 12);
    doc.text(`IFSC: ${profile.ifsc}`, margin, bottomY + 16);

    const signatureX = pageWidth - margin - 60;
    if (profile.signature) {
        try {
            doc.addImage(profile.signature, 'PNG', signatureX, bottomY - 5, 50, 20);
        } catch (e) { console.error("Error adding signature image:", e); }
    }
    doc.line(signatureX, bottomY + 15, signatureX + 50, bottomY + 15);
    doc.text('Authorised Signatory', signatureX + 25, bottomY + 20, { align: 'center' });
    doc.text(`For ${profile.name}`, signatureX + 25, bottomY + 25, { align: 'center' });

    // Footer
    const footerY = pageHeight - margin;
    doc.setFontSize(8);
    doc.setFont('helvetica', 'italic');
    doc.setDrawColor(200);
    doc.line(margin, footerY - 5, pageWidth - margin, footerY - 5);
    doc.text('This is a computer generated document.', pageWidth / 2, footerY, { align: 'center' });

    doc.save(`${docData.docType}-${docData.docNumber}.pdf`);
};

import React, { useState } from 'react';
import { useSettings } from '../contexts/SettingsContext';
import { CompanyProfile } from '../types';

const InputField: React.FC<{ label: string; name: keyof CompanyProfile; value: string; onChange: (e: React.ChangeEvent<HTMLInputElement>) => void; placeholder?: string }> = ({ label, name, value, onChange, placeholder }) => (
    <div>
        <label htmlFor={name} className="block text-sm font-medium text-gray-700">{label}</label>
        <input
            type="text"
            id={name}
            name={name}
            value={value}
            onChange={onChange}
            placeholder={placeholder}
            className="mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm placeholder-gray-400 focus:outline-none focus:ring-primary-500 focus:border-primary-500 sm:text-sm"
        />
    </div>
);

const ImageUploadField: React.FC<{ label: string; name: keyof CompanyProfile; value: string; onChange: (name: keyof CompanyProfile, value: string) => void; }> = ({ label, name, value, onChange }) => {
    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                onChange(name, reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    return (
        <div>
            <label className="block text-sm font-medium text-gray-700">{label}</label>
            <div className="mt-1 flex items-center space-x-4">
                {value && <img src={value} alt={label} className="h-16 w-auto border p-1 rounded-md" />}
                <input
                    type="file"
                    accept="image/png, image/jpeg"
                    onChange={handleFileChange}
                    className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-primary-50 file:text-primary-700 hover:file:bg-primary-100"
                />
            </div>
        </div>
    );
};

