                        <th className="px-2 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider w-2/5">Item Description</th>
                        {doc.gstType === 'gst' && <th className="px-2 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">HSN/SAC</th>}
                        <th className="px-2 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Qty</th>
                        <th className="px-2 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Rate</th>
                        {doc.gstType === 'gst' && <th className="px-2 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">GST</th>}
                        <th className="px-2 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Amount</th>
                        <th className="w-10"></th>
                    </tr>
                </thead>
                <tbody>
                    {doc.items.map((item) => (
                        <tr key={item.id}>
                            <td className="pr-2 py-2 align-top">
                                <input type="text" placeholder="Item/Service" value={item.description} onChange={e => handleItemChange(item.id, 'description', e.target.value)} className="w-full p-1 border-b"/>
                                <textarea placeholder="Additional details..." value={item.details || ''} onChange={e => handleItemChange(item.id, 'details', e.target.value)} className="w-full p-1 mt-1 text-xs text-gray-600 border-b" rows={2}></textarea>
                            </td>
                            {doc.gstType === 'gst' && <td className="px-2 py-2 align-top"><input type="text" value={item.hsn} onChange={e => handleItemChange(item.id, 'hsn', e.target.value)} className="w-full p-1 border-b"/></td>}
                            <td className="px-2 py-2 align-top"><input type="number" value={item.quantity} onChange={e => handleItemChange(item.id, 'quantity', parseFloat(e.target.value))} className="w-20 p-1 border-b"/></td>
                            <td className="px-2 py-2 align-top"><input type="number" value={item.rate} onChange={e => handleItemChange(item.id, 'rate', parseFloat(e.target.value))} className="w-24 p-1 border-b"/></td>
                            {doc.gstType === 'gst' && <td className="px-2 py-2 align-top">
                                <select value={item.gstRate} onChange={e => handleItemChange(item.id, 'gstRate', parseInt(e.target.value))} className="w-full p-1 border-b bg-white">
                                    {GST_RATES.map(r => <option key={r} value={r}>{r}%</option>)}
                                </select>
                            </td>}
                            <td className="px-2 py-2 text-right align-top">{(item.quantity * item.rate).toFixed(2)}</td>
                            <td className="pl-2 py-2 align-top"><button onClick={() => removeItem(item.id)} className="text-red-500 hover:text-red-700 p-1">&times;</button></td>
                        </tr>
                    ))}
                </tbody>
            </table>
            <button onClick={addItem} className="mt-2 text-sm text-primary-600 hover:underline">+ Add Item</button>
        </div>

        {/* Totals & Footer */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mt-8">
            <div>
                <label className="block text-sm font-medium text-gray-700">Terms & Conditions</label>
                <textarea name="terms" value={doc.terms} onChange={handleDocChange} rows={4} className="mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm sm:text-sm"></textarea>
            </div>
            <div className="text-right space-y-2">
                <div className="flex justify-between"><span className="font-semibold">Subtotal:</span><span>₹{subtotal.toFixed(2)}</span></div>
                {doc.gstType === 'gst' && (
                    doc.isInterstate ? 
                    <div className="flex justify-between"><span className="font-semibold">IGST:</span><span>₹{totalTax.toFixed(2)}</span></div>
                    : <>
                        <div className="flex justify-between"><span className="font-semibold">CGST:</span><span>₹{(totalTax/2).toFixed(2)}</span></div>
                        <div className="flex justify-between"><span className="font-semibold">SGST:</span><span>₹{(totalTax/2).toFixed(2)}</span></div>
                    </>
                )}
                <div className="flex justify-between text-xl font-bold border-t pt-2"><span className="">Grand Total:</span><span>₹{grandTotal.toFixed(2)}</span></div>
                <p className="text-xs text-gray-500">{numberToWords(grandTotal)}</p>
            </div>
        </div>

        {/* Actions */}
        <div className="flex justify-end space-x-4 mt-8 border-t pt-6">
            <button onClick={onClose} className="px-6 py-2 bg-gray-200 text-gray-700 font-semibold rounded-md shadow-sm hover:bg-gray-300">Cancel</button>
            <button onClick={() => generatePdf(doc, profile)} className="px-6 py-2 bg-green-600 text-white font-semibold rounded-md shadow-sm hover:bg-green-700">Download PDF</button>
            <button onClick={() => onSave(doc)} className="px-6 py-2 bg-primary-600 text-white font-semibold rounded-md shadow-sm hover:bg-primary-700">Save Document</button>
        </div>

        {/* Customer Modal */}
        {showCustomerModal && (
            <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
                <div className="bg-white p-6 rounded-lg shadow-xl w-full max-w-md">
                    <h3 className="text-lg font-bold mb-4">{newCustomer.id ? 'Edit' : 'Add'} Customer</h3>
                    <div className="space-y-4">
                        <input type="text" placeholder="Name" value={newCustomer.name} onChange={e => setNewCustomer(c => ({...c, name: e.target.value}))} className="w-full p-2 border rounded"/>
                        <input type="text" placeholder="Address" value={newCustomer.address} onChange={e => setNewCustomer(c => ({...c, address: e.target.value}))} className="w-full p-2 border rounded"/>
                        <input type="text" placeholder="City, State - Pincode" value={newCustomer.cityStatePincode} onChange={e => setNewCustomer(c => ({...c, cityStatePincode: e.target.value}))} className="w-full p-2 border rounded"/>
                        <input type="text" placeholder="GSTIN (Optional)" value={newCustomer.gstin} onChange={e => setNewCustomer(c => ({...c, gstin: e.target.value}))} className="w-full p-2 border rounded"/>
                    </div>
                    <div className="flex justify-end space-x-2 mt-6">
                        <button onClick={() => setShowCustomerModal(false)} className="px-4 py-2 bg-gray-200 rounded">Cancel</button>
                        <button onClick={handleSaveCustomer} className="px-4 py-2 bg-primary-600 text-white rounded">Save Customer</button>
                    </div>
                </div>
            </div>
        )}
      </div>
    );
};

export default DocumentEditor;

export interface CompanyProfile {
    name: string;
    address: string;
    cityStatePincode: string;
    country: string;
    gstin: string;
    pan: string;
    phone: string;
    email: string;
    logo: string; // base64 string
    signature: string; // base64 string
    bankName: string;
    branch: string;
    accountNumber: string;
    ifsc: string;
}

export interface Customer {
    id: string;
    name: string;
    address: string;
    cityStatePincode: string;
    country: string;
    gstin: string;
}

export interface LineItem {
    id: string;
    description: string;
    details?: string;
    hsn: string;
    quantity: number;
    rate: number;
    gstRate: number; // as a percentage, e.g., 18 for 18%
}

export type DocumentType = 'invoice' | 'quotation';
export type GstType = 'gst' | 'non-gst';

export interface PdfVisibility {
    showLogo: boolean;
    showBankDetails: boolean;
    showSignature: boolean;
    showTerms: boolean;
}

export interface Document {
    id: string;
    docNumber: string;
    docType: DocumentType;
    gstType: GstType;
    date: string; // YYYY-MM-DD
    dueDate?: string; // For invoices
    validTill?: string; // For quotations
    customer: Customer;
    items: LineItem[];
    terms: string;
    notes: string;
    isInterstate: boolean;
    pdfSettings: PdfVisibility;
}

import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { CompanyProfile, Document } from '../types';
import { numberToWords } from './numberToWords';

export const generatePdf = (docData: Document, profile: CompanyProfile) => {
    const doc = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });

    const pageHeight = doc.internal.pageSize.getHeight();
    const pageWidth = doc.internal.pageSize.getWidth();
    const margin = 10;
    const contentWidth = pageWidth - margin * 2;
    let yPos = margin;

    const docTitle = docData.docType === 'invoice' ? 'TAX INVOICE' : 'QUOTATION';
    const { pdfSettings } = docData;

    // --- HEADER ---
    const headerLeftX = margin;
    const headerRightX = pageWidth - margin;

    if (pdfSettings.showLogo && profile.logo) {
        try {
            doc.addImage(profile.logo, 'PNG', headerLeftX, yPos, 25, 25);
        } catch (e) { console.error("Error adding logo image:", e); }
    }

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(18);
    doc.text(profile.name, headerLeftX + (pdfSettings.showLogo ? 28 : 0), yPos + 7);

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(9);
    doc.text(profile.address, headerLeftX + (pdfSettings.showLogo ? 28 : 0), yPos + 13);
    doc.text(`${profile.cityStatePincode}, ${profile.country}`, headerLeftX + (pdfSettings.showLogo ? 28 : 0), yPos + 17);

    doc.setFont('helvetica', 'bold');
    doc.text('Email:', headerRightX, yPos + 13, { align: 'right' });
    doc.text('Phone:', headerRightX, yPos + 17, { align: 'right' });
    doc.setFont('helvetica', 'normal');
    doc.text(profile.email, headerRightX - 10, yPos + 13, { align: 'right' });
    doc.text(profile.phone, headerRightX - 10, yPos + 17, { align: 'right' });

    yPos += 28;
    doc.setLineWidth(0.5);
    doc.line(margin, yPos, pageWidth - margin, yPos);
    yPos += 2;

    if (docData.gstType === 'gst') {
        doc.setFont('helvetica', 'bold');
        doc.text(`GSTIN: ${profile.gstin}`, pageWidth / 2, yPos + 5, { align: 'center' });
        yPos += 8;
    }

    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.text(docTitle, pageWidth / 2, yPos + 5, { align: 'center' });
    if(docData.docType === 'invoice') {
        doc.setFontSize(8);
        doc.setFont('helvetica', 'normal');
        doc.text('Original for Recipient', pageWidth / 2, yPos + 9, { align: 'center' });
    }
    yPos += 12;

    // --- CUSTOMER & DOC DETAILS ---
    doc.setLineWidth(0.2);
    doc.rect(margin, yPos, contentWidth, 25);
    doc.line(pageWidth / 2, yPos, pageWidth / 2, yPos + 25);

    doc.setFontSize(9);
    doc.setFont('helvetica', 'bold');
    doc.text('Customer Details (Bill to):', margin + 2, yPos + 5);
    doc.setFont('helvetica', 'normal');
    doc.text(docData.customer.name, margin + 2, yPos + 10);
    const addressLines = doc.splitTextToSize(`${docData.customer.address}, ${docData.customer.cityStatePincode}`, (contentWidth / 2) - 5);
    doc.text(addressLines, margin + 2, yPos + 14);
    if(docData.customer.gstin) {
      doc.text(`GSTIN: ${docData.customer.gstin}`, margin + 2, yPos + 22);
    }

    const rightColX = pageWidth / 2 + 2;
    doc.setFont('helvetica', 'bold');
    doc.text(`${docData.docType === 'invoice' ? 'Invoice' : 'Quotation'} No:`, rightColX, yPos + 5);
    doc.text('Date:', rightColX, yPos + 10);
    if (docData.docType === 'invoice') doc.text('Due Date:', rightColX, yPos + 15);
    else doc.text('Valid Till:', rightColX, yPos + 15);

    doc.setFont('helvetica', 'normal');
    doc.text(docData.docNumber, rightColX + 25, yPos + 5);
    doc.text(new Date(docData.date).toLocaleDateString('en-GB'), rightColX + 25, yPos + 10);
    if (docData.docType === 'invoice' && docData.dueDate) doc.text(new Date(docData.dueDate).toLocaleDateString('en-GB'), rightColX + 25, yPos + 15);
    if (docData.docType === 'quotation' && docData.validTill) doc.text(new Date(docData.validTill).toLocaleDateString('en-GB'), rightColX + 25, yPos + 15);

    yPos += 30;

    // --- ITEMS TABLE ---
    const subtotal = docData.items.reduce((acc, item) => acc + item.quantity * item.rate, 0);
    let totalTax = 0;
    const isGst = docData.gstType === 'gst';

    const head = isGst ? 
      (docData.isInterstate ? 
        [['#', 'Item & Description', 'HSN', 'Taxable Value', 'IGST %', 'IGST Amt', 'Total']] : 
        [
          [{ content: '#', rowSpan: 2 }, { content: 'Item & Description', rowSpan: 2 }, { content: 'HSN', rowSpan: 2 }, { content: 'Taxable Value', rowSpan: 2 }, { content: 'CGST', colSpan: 2 }, { content: 'SGST', colSpan: 2 }, { content: 'Total', rowSpan: 2 }],
          ['%', 'Amount', '%', 'Amount']
        ])
      : [['#', 'Item & Description', 'Qty', 'Rate (₹)', 'Amount (₹)']];

    const body = docData.items.map((item, index) => {
        const taxableValue = item.quantity * item.rate;
        const itemFullDescription = `${item.description}\n${item.details || ''}`.trim();

        if(isGst) {
          const tax = taxableValue * (item.gstRate / 100);
          totalTax += tax;
          const total = taxableValue + tax;
          if(docData.isInterstate) {
            return [index + 1, itemFullDescription, item.hsn, taxableValue.toFixed(2), `${item.gstRate}%`, tax.toFixed(2), total.toFixed(2)];
          } else {
            return [index + 1, itemFullDescription, item.hsn, taxableValue.toFixed(2), `${item.gstRate/2}%`, (tax/2).toFixed(2), `${item.gstRate/2}%`, (tax/2).toFixed(2), total.toFixed(2)];
          }
        } else {
            return [index + 1, itemFullDescription, item.quantity, item.rate.toFixed(2), taxableValue.toFixed(2)];
        }
    });

    const grandTotal = subtotal + totalTax;

    autoTable(doc, {
        head: head,
        body: body,
        startY: yPos,
        theme: 'grid',
        headStyles: { fillColor: [41, 128, 185], textColor: 255, fontStyle: 'bold', halign: 'center' },
        styles: { fontSize: 9, cellPadding: 2, valign: 'middle' },
        columnStyles: {
            0: { halign: 'center', cellWidth: 10 },
            1: { cellWidth: isGst ? 60 : 80 },
        },
        didDrawPage: (data) => {
            // Footer
            doc.setFontSize(8);
            doc.setFont('helvetica', 'italic');
            doc.text(`Page ${data.pageNumber}`, pageWidth / 2, pageHeight - 5, { align: 'center' });
            doc.text('This is an electronically generated document, no signature is required.', margin, pageHeight - 5);
        }
    });

    yPos = (doc as any).lastAutoTable.finalY;

    // --- TOTALS ---
    const summaryRightX = pageWidth - margin;
    const summaryLeftX = summaryRightX - 60;

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text('Total in words:', margin, yPos + 8);
    doc.setFont('helvetica', 'bold');
    doc.text(numberToWords(grandTotal), margin, yPos + 13, { maxWidth: contentWidth - 70 });

    doc.setFont('helvetica', 'normal');
    doc.text('Taxable Amount:', summaryLeftX, yPos + 8, { align: 'left' });
    doc.text(`₹${subtotal.toFixed(2)}`, summaryRightX, yPos + 8, { align: 'right' });

    if(isGst) {
      if (docData.isInterstate) {
        doc.text('Add: IGST:', summaryLeftX, yPos + 14, { align: 'left' });
        doc.text(`₹${totalTax.toFixed(2)}`, summaryRightX, yPos + 14, { align: 'right' });
      } else {
        doc.text('Add: CGST:', summaryLeftX, yPos + 14, { align: 'left' });
        doc.text(`₹${(totalTax / 2).toFixed(2)}`, summaryRightX, yPos + 14, { align: 'right' });
        doc.text('Add: SGST:', summaryLeftX, yPos + 20, { align: 'left' });
        doc.text(`₹${(totalTax / 2).toFixed(2)}`, summaryRightX, yPos + 20, { align: 'right' });
      }
    }

    doc.setLineWidth(0.3);
    doc.line(summaryLeftX - 2, yPos + (isGst && !docData.isInterstate ? 24 : 18) , summaryRightX, yPos + (isGst && !docData.isInterstate ? 24 : 18));

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(11);
    doc.text('Total Amount:', summaryLeftX, yPos + (isGst && !docData.isInterstate ? 29 : 23), { align: 'left' });
    doc.text(`₹${grandTotal.toFixed(2)}`, summaryRightX, yPos + (isGst && !docData.isInterstate ? 29 : 23), { align: 'right' });

    // --- BANK, TERMS, SIGNATURE ---
    const bottomY = pageHeight - margin - (pdfSettings.showSignature ? 40 : 10);
    const thirdWidth = contentWidth / 3;

    if (pdfSettings.showBankDetails) {
        doc.setFontSize(9);
        doc.setFont('helvetica', 'bold');
        doc.text('Bank Details:', margin, bottomY);
        doc.setFont('helvetica', 'normal');
        doc.setFontSize(8);
        doc.text(`Bank: ${profile.bankName}`, margin, bottomY + 5);
        doc.text(`A/c: ${profile.accountNumber}`, margin, bottomY + 9);
        doc.text(`Branch: ${profile.branch}`, margin, bottomY + 13);
        doc.text(`IFSC: ${profile.ifsc}`, margin, bottomY + 17);
    }

    if (pdfSettings.showTerms) {
        doc.setFontSize(9);
        doc.setFont('helvetica', 'bold');
        doc.text('Terms & Conditions:', margin + thirdWidth + 5, bottomY);
        doc.setFont('helvetica', 'normal');
        doc.setFontSize(7);
        doc.text(docData.terms, margin + thirdWidth + 5, bottomY + 5, { maxWidth: thirdWidth - 5 });
    }

    if (pdfSettings.showSignature) {
        const signatureX = margin + 2 * thirdWidth + 10;
        const signatureY = bottomY;
        doc.setFontSize(9);
        doc.setFont('helvetica', 'bold');
        doc.text(`For ${profile.name}`, signatureX, signatureY, { align: 'center', maxWidth: thirdWidth });
        if (profile.signature) {
            try {
                doc.addImage(profile.signature, 'PNG', signatureX, signatureY + 2, thirdWidth, 15);
            } catch (e) { console.error("Error adding signature image:", e); }
        }
        doc.line(signatureX, signatureY + 25, signatureX + thirdWidth, signatureY + 25);
        doc.setFont('helvetica', 'normal');
        doc.setFontSize(8);
        doc.text('Authorised Signatory', signatureX + (thirdWidth/2), signatureY + 29, { align: 'center' });
    }

    doc.save(`${docData.docType}-${docData.docNumber}.pdf`);
};

import React, { useState, useEffect, useMemo } from 'react';
import { Document, Customer, LineItem, DocumentType, GstType } from '../types';
import { useLocalStorage } from '../hooks/useLocalStorage';
import { BLANK_CUSTOMER, GST_RATES, DEFAULT_TERMS } from '../constants';
import { useSettings } from '../contexts/SettingsContext';
import { numberToWords } from '../services/numberToWords';
import { generatePdf } from '../services/pdfGenerator';
import { v4 as uuidv4 } from 'uuid'; // Need to add @types/uuid for types if not present


const DocumentEditor: React.FC<{
    initialDoc: Partial<Document>;
    onSave: (doc: Document) => void;
    onClose: () => void;
    documents: Document[];
}> = ({ initialDoc, onSave, onClose, documents }) => {
    const { profile } = useSettings();
    const [doc, setDoc] = useState<Document>(() => createInitialDocumentState());
    const [customers, setCustomers] = useLocalStorage<Customer[]>('customers', []);
    const [showCustomerModal, setShowCustomerModal] = useState(false);
    const [newCustomer, setNewCustomer] = useState<Customer>(BLANK_CUSTOMER);

    function createInitialDocumentState(): Document {
        const nextDocNumber = getNextDocNumber(initialDoc.docType!, initialDoc.gstType!);
        const today = new Date().toISOString().split('T')[0];
        const dueDate = new Date();
        dueDate.setDate(dueDate.getDate() + 30);
        const validTill = new Date();
        validTill.setDate(validTill.getDate() + 15);

        return {
            id: initialDoc.id || uuidv4(),
            docNumber: initialDoc.docNumber || nextDocNumber,
            docType: initialDoc.docType!,
            gstType: initialDoc.gstType!,
            date: initialDoc.date || today,
            dueDate: initialDoc.dueDate || (initialDoc.docType === 'invoice' ? dueDate.toISOString().split('T')[0] : undefined),
            validTill: initialDoc.validTill || (initialDoc.docType === 'quotation' ? validTill.toISOString().split('T')[0] : undefined),
            customer: initialDoc.customer || BLANK_CUSTOMER,
            items: initialDoc.items || [{ id: uuidv4(), description: '', details: '', hsn: '', quantity: 1, rate: 0, gstRate: 18 }],
            terms: initialDoc.terms || DEFAULT_TERMS,
            notes: initialDoc.notes || '',
            isInterstate: initialDoc.isInterstate || false,
            pdfSettings: initialDoc.pdfSettings || {
                showLogo: true,
                showBankDetails: true,
                showSignature: true,
                showTerms: true,
            },
        };
    }

    function getNextDocNumber(docType: DocumentType, gstType: GstType): string {
        const prefix = `${docType.slice(0, 3).toUpperCase()}/${gstType.slice(0, 3).toUpperCase()}/`;
        const relevantDocs = documents.filter(d => d.docType === docType && d.gstType === gstType);
        if (relevantDocs.length === 0) return `${prefix}001`;

        const maxNum = Math.max(...relevantDocs.map(d => parseInt(d.docNumber.split('/').pop() || '0', 10)));
        return `${prefix}${(maxNum + 1).toString().padStart(3, '0')}`;
    }

    useEffect(() => {
        if (profile.cityStatePincode && doc.customer.cityStatePincode) {
            const sellerState = profile.cityStatePincode.split(',')[1]?.trim().toLowerCase();
            const customerState = doc.customer.cityStatePincode.split(',')[1]?.trim().toLowerCase();
            setDoc(d => ({ ...d, isInterstate: sellerState !== customerState }));
        }
    }, [profile.cityStatePincode, doc.customer.cityStatePincode]);

    const handleDocChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setDoc(prev => ({ ...prev, [name]: value }));
    };

    const handleItemChange = (id: string, field: keyof LineItem, value: string | number) => {
        setDoc(prev => ({
            ...prev,
            items: prev.items.map(item =>
                item.id === id ? { ...item, [field]: value } : item
            )
        }));
    };

    const addItem = () => {
        setDoc(prev => ({
            ...prev,
            items: [...prev.items, { id: uuidv4(), description: '', details: '', hsn: '', quantity: 1, rate: 0, gstRate: 18 }]
        }));
    };

    const removeItem = (id: string) => {
        setDoc(prev => ({ ...prev, items: prev.items.filter(item => item.id !== id) }));
    };

    const handleSelectCustomer = (customerId: string) => {
        const selected = customers.find(c => c.id === customerId);
        if (selected) {
            setDoc(prev => ({ ...prev, customer: selected }));
        } else {
            setDoc(prev => ({ ...prev, customer: BLANK_CUSTOMER }));
        }
    };

    const handleSaveCustomer = () => {
        if(newCustomer.name) {
            const customerToSave = { ...newCustomer, id: newCustomer.id || uuidv4() };
            setCustomers(prev => {
                const existing = prev.find(c => c.id === customerToSave.id);
                if (existing) {
                    return prev.map(c => c.id === customerToSave.id ? customerToSave : c);
                }
                return [...prev, customerToSave];
            });
            setDoc(prev => ({ ...prev, customer: customerToSave}));
            setShowCustomerModal(false);
            setNewCustomer(BLANK_CUSTOMER);
        }
    };

    const handlePdfSettingsChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, checked } = e.target;
        setDoc(prev => ({
            ...prev,
            pdfSettings: {
                ...prev.pdfSettings,
                [name]: checked,
            }
        }));
    };

    const subtotal = useMemo(() => doc.items.reduce((acc, item) => acc + item.quantity * item.rate, 0), [doc.items]);
    const totalTax = useMemo(() => doc.gstType === 'gst' ? doc.items.reduce((acc, item) => acc + (item.quantity * item.rate * item.gstRate / 100), 0) : 0, [doc.items, doc.gstType]);
    const grandTotal = subtotal + totalTax;

    const docTitle = `${doc.gstType.toUpperCase()} ${doc.docType.charAt(0).toUpperCase() + doc.docType.slice(1)}`;

    return (
      <div className="bg-white p-8 rounded-lg shadow-lg">
